import androidx.compose.ui.res.stringResource
import androidx.compose.ui.text.TextStyle
import androidx.compose.ui.text.style.TextOverflow
import androidx.compose.ui.unit.Dp
import androidx.compose.ui.unit.dp
import com.songs.core.ui.R

enum class MediaItemComponentStyle {
    ROW, COLUMN;
}

/**
 * Base composable shared by [SongItemComponent] and [AlbumItemComponent].
 */
@Composable
internal fun MediaItemComponent(
    title: String,
    subtitle: String,
    artworkUrl: String?,
    artworkSize: Dp,
    artworkCornerRadius: Dp,
    style: MediaItemComponentStyle,
    titleStyle: @Composable () -> TextStyle,
    subtitleStyle: @Composable () -> TextStyle,
    subtitleAlpha: Float,
    modifier: Modifier = Modifier,
    isClickable: Boolean,
    showNavOption: Boolean,
    isPlaying: Boolean,
    onMenuClick: () -> Unit = { },
    onClick: () -> Unit = {},
) {
    when (style) {
        MediaItemComponentStyle.ROW -> RowMediaItemComponent(
            title = title,
            subtitle = subtitle,
            artworkUrl = artworkUrl,
            artworkSize = artworkSize,
            artworkCornerRadius = artworkCornerRadius,
            titleStyle = titleStyle,
            subtitleStyle = subtitleStyle,
            subtitleAlpha = subtitleAlpha,
            modifier = modifier,
            isClickable = isClickable,
            showNavOption = showNavOption,
            isPlaying = isPlaying,
            onClick = onClick,
            onMenuClick = onMenuClick,
        )

        MediaItemComponentStyle.COLUMN -> ColumnMediaItemComponent(
            title = title,
            subtitle = subtitle,
            artworkUrl = artworkUrl,
            artworkSize = artworkSize,
            artworkCornerRadius = artworkCornerRadius,
            titleStyle = titleStyle,
            subtitleStyle = subtitleStyle,
            subtitleAlpha = subtitleAlpha,
            modifier = modifier,
            isClickable = isClickable,
            isPlaying = isPlaying,
            onClick = onClick,
        )
    }
}

@Composable
fun RowMediaItemComponent(
    title: String,
    subtitle: String,
    artworkUrl: String?,
    artworkSize: Dp,
    artworkCornerRadius: Dp,
    titleStyle: @Composable () -> TextStyle,
    subtitleStyle: @Composable () -> TextStyle,
    subtitleAlpha: Float,
    modifier: Modifier = Modifier,
    isClickable: Boolean = true,
    showNavOption: Boolean = true,
    isPlaying: Boolean = false,
    onClick: () -> Unit = {},
    onMenuClick: () -> Unit,
) {
    var isMenuExpanded by remember { mutableStateOf(false) }

    Row(
        modifier = modifier
            .fillMaxWidth()
            .clickable(enabled = isClickable) { onClick() },
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        if (!artworkUrl.isNullOrEmpty()) {
            AlbumCover(
                imageUrl = artworkUrl,
                cornerRadius = artworkCornerRadius,
                size = artworkSize,
            )
        }

        AlbumTitleAndArtist(
            title = title,
            titleStyle = titleStyle,
            subtitle = subtitle,
            subtitleStyle = subtitleStyle,
            subtitleAlpha = subtitleAlpha
        )

        if (showNavOption) {
            Box {
                OptionsIconButton(
                    isMenuExpanded = isMenuExpanded,
                    onMenuClick = {
                        isMenuExpanded = it
                        onMenuClick()
                    },
                )
            }
        }

        if (isPlaying) {
            Image(
                painter = painterResource(id = R.drawable.playing_animation_icon),
                contentDescription = stringResource(R.string.playing),
                modifier = Modifier.size(32.dp)
            )
        }
    }
}

@Composable
fun ColumnMediaItemComponent(
    title: String,
    subtitle: String,
    artworkUrl: String?,
    artworkSize: Dp,
    artworkCornerRadius: Dp,
    titleStyle: @Composable () -> TextStyle,
    subtitleStyle: @Composable () -> TextStyle,
    subtitleAlpha: Float,
    modifier: Modifier = Modifier,
    isClickable: Boolean = true,
    isPlaying: Boolean = false,
    onClick: () -> Unit = {},
) {
    Column(
        modifier = modifier
            .fillMaxWidth()
            .clickable(enabled = isClickable) { onClick() },
        verticalArrangement = Arrangement.spacedBy(4.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
    ) {
        if (!artworkUrl.isNullOrEmpty()) {
            AlbumCover(
                imageUrl = artworkUrl,
                modifier = Modifier.fillMaxSize(),
                cornerRadius = artworkCornerRadius,
                size = artworkSize,
            )
        }

        AlbumTitleAndArtist(
            title = title,
            titleStyle = titleStyle,
            subtitle = subtitle,
            subtitleStyle = subtitleStyle,
            subtitleAlpha = subtitleAlpha
        )

        if (isPlaying) {
            Image(
                painter = painterResource(id = R.drawable.playing_animation_icon),
                contentDescription = stringResource(R.string.playing),
                modifier = Modifier.size(32.dp)
            )
        }
    }
}

@Composable
private fun ColumnScope.AlbumTitleAndArtist(
    title: String,
    titleStyle: @Composable (() -> TextStyle),
    subtitle: String,
    subtitleStyle: @Composable (() -> TextStyle),
    subtitleAlpha: Float
) {
    Column(
        modifier = Modifier.weight(1f),
        verticalArrangement = Arrangement.spacedBy(4.dp, Alignment.CenterVertically)
    ) {
        Text(
            text = title,
            style = titleStyle(),
            color = MaterialTheme.colorScheme.onBackground,
            maxLines = 1,
            overflow = TextOverflow.Ellipsis,
        )
        Text(
            text = subtitle,
            style = subtitleStyle(),
            color = MaterialTheme.colorScheme.onBackground.copy(alpha = subtitleAlpha),
            maxLines = 1,
            overflow = TextOverflow.Ellipsis,
        )
    }
}

@Composable
private fun RowScope.AlbumTitleAndArtist(
    title: String,
    titleStyle: @Composable (() -> TextStyle),
    subtitle: String,
    subtitleStyle: @Composable (() -> TextStyle),
    subtitleAlpha: Float
) {
    Column(
        modifier = Modifier.weight(1f),
        verticalArrangement = Arrangement.spacedBy(4.dp, Alignment.CenterVertically)
    ) {
        Text(
            text = title,
            style = titleStyle(),
            color = MaterialTheme.colorScheme.onBackground,
            maxLines = 1,
            overflow = TextOverflow.Ellipsis,
        )
        Text(
            text = subtitle,
            style = subtitleStyle(),
            color = MaterialTheme.colorScheme.onBackground.copy(alpha = subtitleAlpha),
            maxLines = 1,
            overflow = TextOverflow.Ellipsis,
        )
    }
}

@Composable
private fun OptionsIconButton(
    isMenuExpanded: Boolean,
    onMenuClick: (Boolean) -> Unit,
) {
    IconButton(onClick = { onMenuClick(true) }) {
        Icon(
            imageVector = Icons.Default.MoreVert,
            contentDescription = stringResource(R.string.menu),
            tint = MaterialTheme.colorScheme.onBackground.copy(alpha = 0.3f)
        )
    }
    DropdownMenu(
        expanded = isMenuExpanded,
        onDismissRequest = { onMenuClick(false) }
    ) {
        DropdownMenuItem(
            text = {
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(8.dp),
                    verticalAlignment = Alignment.CenterVertically,
                    horizontalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    Text(
                        text = stringResource(R.string.view_album),
                        modifier = Modifier.weight(1f),
                        color = MaterialTheme.colorScheme.onBackground
                    )
                    Icon(
                        imageVector = Icons.Default.ChevronRight,
                        contentDescription = stringResource(R.string.chevron),
                        tint = MaterialTheme.colorScheme.onBackground,
                        modifier = Modifier.size(20.dp)
                    )
                }
            },
            onClick = { onMenuClick(false) }
        )
    }
}

