@Composable fun MiniPlayer( isPlayerScreenVisible: Boolean, onNavigateToPlayer: (trackIds: List<Long>, currentTrackId: Long) -> Unit, modifier: Modifier = Modifier, viewModel: MiniPlayerViewModel = hiltViewModel(), ) { val uiState by viewModel.uiState.collectAsStateWithLifecycle()
