package com.songs.navigation

import androidx.compose.animation.core.tween
import androidx.compose.animation.slideInVertically
import androidx.compose.animation.slideOutVertically
import androidx.compose.animation.togetherWith
import androidx.compose.runtime.Composable
import androidx.navigation3.runtime.entryProvider
import androidx.navigation3.runtime.rememberNavBackStack
import androidx.navigation3.ui.NavDisplay
import androidx.navigation3.ui.defaultPopTransitionSpec
import androidx.navigation3.ui.defaultTransitionSpec
import com.songs.home.presentation.ui.album.AlbumScreen
import com.songs.home.presentation.ui.songs.SongsScreen
import com.songs.navigation.route.AlbumRoute
import com.songs.navigation.route.HomeRoute
import com.songs.navigation.route.PlayerRoute
import com.songs.navigation.route.SplashRoute
import com.songs.player.presentation.ui.PlayerScreen
import com.songs.splash.presentation.screens.SplashScreen

@Composable
fun NavigationGraph() {
    val backStack = rememberNavBackStack(SplashRoute)

    fun navigateToPlayer(trackIds: List<Long>, currentTrackId: Long) {
        val playerRoute = PlayerRoute(trackIds, currentTrackId)
        val existingIndex = backStack.indexOfFirst { it is PlayerRoute }
        if (existingIndex >= 0) backStack.removeAt(existingIndex)
        backStack.add(playerRoute)
    }

    NavDisplay(
        backStack = backStack,
        onBack = { backStack.removeLastOrNull() },
        transitionSpec = {
            val toPlayer = targetState.entries.any { it.key is PlayerRoute }
            if (toPlayer) {
                slideInVertically(tween(400)) { it } togetherWith
                    slideOutVertically(tween(400)) { -it }
            } else {
                defaultTransitionSpec<Any>().invoke(this)
            }
        },
        popTransitionSpec = {
            val fromPlayer = initialState.entries.any { it.key is PlayerRoute }
            if (fromPlayer) {
                slideInVertically(tween(400)) { -it } togetherWith
                    slideOutVertically(tween(400)) { it }
            } else {
                defaultPopTransitionSpec<Any>().invoke(this)
            }
        },
        entryProvider = entryProvider {
            entry<SplashRoute> {
                SplashScreen(
                    onAnimationFinished = { backStack.add(HomeRoute) }
                )
            }
            entry<HomeRoute> {
                SongsScreen(
                    onNavigateToAlbum = { albumId -> backStack.add(AlbumRoute(albumId)) },
                    onNavigateToPlayer = ::navigateToPlayer
                )
            }
            entry<AlbumRoute> { route ->
                AlbumScreen(
                    albumId = route.albumId,
                    onNavigateUp = { backStack.removeLastOrNull() },
                    onNavigateToPlayer = ::navigateToPlayer
                )
            }
            entry<PlayerRoute> { route ->
                PlayerScreen(
                    trackIds = route.trackIds,
                    currentTrackId = route.currentTrackId,
                    onNavigateUp = { backStack.removeLastOrNull() },
                    onNavigateToAlbum = { albumId -> backStack.add(AlbumRoute(albumId)) }
                )
            }
        }
    )
}

