@Composable
internal fun RowScope.Player(
    uiState: PlayerUiState,
    currentTrackId: Long,
    modifier: Modifier = Modifier,
    onNavigateUp: () -> Unit,
    onNavigateToAlbum: (String) -> Unit,
    onPlayPauseClick: () -> Unit,
    onRewindClick: () -> Unit,
    onForwardClick: () -> Unit,
    onRepeatClick: () -> Unit,
    onSliderPositionChange: (Long) -> Unit,
) {
    when (uiState) {
        is PlayerUiState.Error -> {
            Text(
                text = stringResource(R.string.error_loading_song),
                color = MaterialTheme.colorScheme.error,
                modifier = Modifier.align(Alignment.CenterVertically)
            )
        }

        is PlayerUiState.Loading -> {
            LoadingScreen()
        }

        is PlayerUiState.Success -> {
            InternalPlayer(
                modifier = modifier,
                onNavigateUp = onNavigateUp,
                onNavigateToAlbum = onNavigateToAlbum,
                uiState = uiState,
                currentTrackId = currentTrackId,
                onSliderPositionChange = onSliderPositionChange,
                onPlayPauseClick = onPlayPauseClick,
                onRewindClick = onRewindClick,
                onForwardClick = onForwardClick,
                onRepeatClick = onRepeatClick,
            )
        }
    }
}

@OptIn(ExperimentalSharedTransitionApi::class)
@Composable
private fun InternalPlayer(
    modifier: Modifier = Modifier,
    onNavigateUp: () -> Unit,
    onNavigateToAlbum: (String) -> Unit,
    uiState: PlayerUiState.Success,
    currentTrackId: Long,
    onSliderPositionChange: (Long) -> Unit,
    onPlayPauseClick: () -> Unit,
    onRewindClick: () -> Unit,
    onForwardClick: () -> Unit,
    onRepeatClick: () -> Unit,
) {
    val sharedTransitionScope = LocalSharedTransitionScope.current
    val animatedContentScope = LocalNavAnimatedContentScope.current

    Column(
        modifier = modifier
            .fillMaxHeight()
            .padding(horizontal = 24.dp, vertical = 16.dp),
        verticalArrangement = Arrangement.SpaceBetween,
    ) {
        Header(
            onNavigateUp = onNavigateUp,
            onNavigateToAlbum = onNavigateToAlbum,
            currentTrack = uiState.currentTrack
        )

        Spacer(Modifier.weight(1f))

        key(uiState.currentTrack?.artworkUrl500) {
        AlbumCover(
            imageUrl = uiState.currentTrack?.artworkUrl500,
            modifier = Modifier
                .align(Alignment.CenterHorizontally)
                .then(
                    if (sharedTransitionScope != null)
                        with(sharedTransitionScope) {
                            Modifier
                                .sharedElement(
                                    sharedContentState = rememberSharedContentState(key = "song_artwork_$currentTrackId"),
                                    animatedVisibilityScope = animatedContentScope,
                                )
                                .skipToLookaheadSize()
                        }
                    else Modifier
                )
        }

        Spacer(Modifier.weight(1f))

        AlbumInfo(
            currentTrack = uiState.currentTrack,
            titleModifier = if (sharedTransitionScope != null)
                with(sharedTransitionScope) {
                    Modifier
                        .sharedElement(
                            sharedContentState = rememberSharedContentState(key = "song_title_$currentTrackId"),
                            animatedVisibilityScope = animatedContentScope,
                        )
                        .skipToLookaheadSize()
                }
            else Modifier,
            subtitleModifier = if (sharedTransitionScope != null)
                with(sharedTransitionScope) {
                    Modifier
                        .sharedElement(
                            sharedContentState = rememberSharedContentState(key = "song_artist_$currentTrackId"),
                            animatedVisibilityScope = animatedContentScope,
                        )
                        .skipToLookaheadSize()
                }
            else Modifier,
        )


        SongProgressTracker(
            sliderPosition = uiState.sliderPosition,
            onSliderPositionChange = onSliderPositionChange,
            duration = uiState.duration,
            formattedCurrentPosition = uiState.formattedCurrentPosition,
            formattedRemainingTime = uiState.formattedRemainingTime,
        )

        PlayerControls(
            isPlaying = uiState.isPlaying,
            isRepeatOn = uiState.isRepeatOn,
            onPlayPauseClick = onPlayPauseClick,
            onRewindClick = onRewindClick,
            onForwardClick = onForwardClick,
            onRepeatClick = onRepeatClick,
        )
    }
}

@Composable
private fun Header(
    onNavigateUp: () -> Unit,
    onNavigateToAlbum: (String) -> Unit,
    currentTrack: Track?
) {
    var isMenuExpanded by remember { mutableStateOf(false) }

    AppHeader(
        title = stringResource(R.string.now_playing),
        navigationIcon = { NavigationIcon(onNavigateUp = onNavigateUp) },
        trailingContent = {
            IconButton(onClick = { isMenuExpanded = true }) {
                Icon(
                    imageVector = Icons.Default.MoreVert,
                    contentDescription = stringResource(R.string.menu),
                    tint = MaterialTheme.colorScheme.onBackground
                )
            }
            DropdownMenu(
                expanded = isMenuExpanded,
                onDismissRequest = { isMenuExpanded = false }
            ) {
                DropdownMenuItem(
                    text = {
                        Row(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(8.dp),
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(8.dp)
                        ) {
                            Text(
                                text = stringResource(R.string.view_album),
                                modifier = Modifier.weight(1f),
                                color = MaterialTheme.colorScheme.onBackground
                            )
                            Icon(
                                imageVector = Icons.Default.ChevronRight,
                                contentDescription = stringResource(R.string.chevron),
                                tint = MaterialTheme.colorScheme.onBackground,
                                modifier = Modifier.size(20.dp)
                            )
                        }
                    },
                    onClick = {
                        currentTrack?.collectionId?.let { collectionId ->
                            onNavigateToAlbum(collectionId.toString())
                        }
                        isMenuExpanded = false
                    }
                )
            }
        }
    )
}

@PhonePreviews
@TabletPreviews
@Composable
private fun Preview(
    @PreviewParameter(TrackPreviewParameterProvider::class, limit = 1) track: Track
) {
    ThemePreview {
        Row {
            Player(
                uiState = PlayerUiState.Success(
                    currentTrack = track,
                    isPlaying = true,
                    isRepeatOn = false,
                    currentPosition = 90000L,
                    duration = track.trackTimeMillis ?: 240000L
                ),
                currentTrackId = 0L,
                onNavigateUp = {},
                onNavigateToAlbum = {},
                onPlayPauseClick = {},
                onRewindClick = {},
                onForwardClick = {},
                onRepeatClick = {},
                onSliderPositionChange = {}
            )
        }
    }
}

