import kotlinx.coroutines.flow.collectLatest

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SongsScreen(
    viewModel: SongsViewModel = hiltViewModel(),
    onNavigateToAlbum: (String) -> Unit,
    onNavigateToPlayer: (trackIds: List<Long>, currentTrackId: Long) -> Unit,
) {
    val searchTerm by viewModel.searchTerm.collectAsStateWithLifecycle()
    var searchTextFieldValue by remember { mutableStateOf(TextFieldValue(searchTerm)) }
    var isSearchActive by remember { mutableStateOf(false) }

    // When search is dismissed, clear the field and revert to default results
    LaunchedEffect(isSearchActive) {
        if (!isSearchActive) {
            searchTextFieldValue = TextFieldValue("")
            viewModel.resetToDefault()
        }
    }
    val pagingDataFlow by viewModel.songsPagingData.collectAsStateWithLifecycle()
    val lazyPagingItems = pagingDataFlow.collectAsLazyPagingItems()
    var showHeader by remember { mutableStateOf(true) }
    val listState = rememberLazyListState()
    val snackbarHostState = remember { SnackbarHostState() }

    // Show network error as a snackbar
    LaunchedEffect(Unit) {
        viewModel.networkErrorEvents.collectLatest { message ->
            snackbarHostState.showSnackbar(
                message = message,
                duration = SnackbarDuration.Short,
            )
        }
    }

    // Track scroll direction to show/hide header
    var previousFirstVisibleIndex by remember { mutableIntStateOf(0) }
    var previousFirstVisibleOffset by remember { mutableIntStateOf(0) }

    LaunchedEffect(listState) {
        snapshotFlow {
            listState.firstVisibleItemIndex to listState.firstVisibleItemScrollOffset
        }.collectLatest { (index, offset) ->
            val scrolledDown = index > previousFirstVisibleIndex
                    || (index == previousFirstVisibleIndex && offset > previousFirstVisibleOffset)
            val scrolledUp = index < previousFirstVisibleIndex
                    || (index == previousFirstVisibleIndex && offset < previousFirstVisibleOffset)
            if (scrolledDown) showHeader = false
            if (scrolledUp) showHeader = true
            previousFirstVisibleIndex = index
            previousFirstVisibleOffset = offset
        }
    }

    Scaffold(
        snackbarHost = { SnackbarHost(snackbarHostState) },
        modifier = Modifier
            .consumeWindowInsets(
                WindowInsets.systemBars.only(WindowInsetsSides.Bottom)
            )
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
        ) {
            Header(
                isVisible = showHeader,
                isSearchActive = isSearchActive,
                onSearchActiveChanged = { isSearchActive = it },
                searchTextFieldValue = searchTextFieldValue,
                searchTextFieldValueChange = { searchTextFieldValue = it },
                onSearchTermChanged = viewModel::onSearchTermChanged,
                modifier = Modifier.padding(top = 32.dp, start = 16.dp, end = 16.dp),
            )

            Spacer(modifier = Modifier.height(24.dp))

            // Only show full-screen states when there are no cached items to display.
            // When items exist (from cache), show them even during a background refresh.
            val isFirstLoad = lazyPagingItems.loadState.refresh is LoadState.Loading
                    && lazyPagingItems.itemCount == 0
            val isFirstLoadError = lazyPagingItems.loadState.refresh is LoadState.Error
                    && lazyPagingItems.itemCount == 0

            when {
                isFirstLoad -> LoadingScreen()

                isFirstLoadError -> {
                    Box(modifier = Modifier.fillMaxSize()) {
                        Text(
                            text = stringResource(R.string.error_loading_songs),
                            color = MaterialTheme.colorScheme.error,
                            modifier = Modifier.align(Alignment.Center)
                        )
                    }
                }

                else -> {
                    val isRefreshing = !isSearchActive
                            && lazyPagingItems.loadState.refresh is LoadState.Loading
                            && lazyPagingItems.itemCount > 0
                    val pullState = rememberPullToRefreshState()

                    val songsList = @Composable {
                        LazyColumn(
                            state = listState,
                            modifier = Modifier.fillMaxWidth(),
                            contentPadding = PaddingValues(horizontal = 16.dp),
                            verticalArrangement = Arrangement.spacedBy(16.dp),
                        ) {
                            items(lazyPagingItems.itemCount) { index ->
                                lazyPagingItems[index]?.let { song ->
                                    SongItemComponent(
                                        title = song.trackName,
                                        subtitle = song.artistName,
                                        artworkUrl = song.artworkUrl100,
                                        modifier = Modifier.animateItem(),
                                        onMenuClick = {
                                            song.collectionId?.let { collectionId ->
                                                onNavigateToAlbum(collectionId.toString())
                                            }
                                        },
                                        onClick = {
                                            val allTrackIds =
                                                (0 until minOf(lazyPagingItems.itemCount, 15))
                                                    .mapNotNull { i -> lazyPagingItems[i]?.trackId }
                                            val currentTrackId = song.trackId ?: 0
                                            onNavigateToPlayer(allTrackIds, currentTrackId)
                                        }
                                    )
                                }
                            }
                            if (lazyPagingItems.loadState.append is LoadState.Loading) {
                                item { LoadingScreen() }
                            }
                        }
                    }

                    if (isSearchActive) {
                        songsList()
                    } else {
                        PullToRefreshBox(
                            state = pullState,
                            isRefreshing = isRefreshing,
                            onRefresh = { viewModel.refresh() },
                            modifier = Modifier.fillMaxSize(),
                            contentAlignment = Alignment.TopCenter,
                        ) {
                            songsList()
                        }
                    }
                }
            }
        }
    }
}

